sql:
SELECT b.borough_name
FROM boroughs b
WHERE b.average_income > 35000 AND b.happiness_score > 7.0;

SELECT COUNT(feedback_id) AS feedback_count
FROM residents_feedback
WHERE borough_id = 1;

SELECT borough_name
FROM boroughs
ORDER BY average_income DESC, health_index DESC;

SELECT borough_name
FROM boroughs
ORDER BY borough_name;

SELECT AVG(health_index) AS average_health_index
FROM boroughs
WHERE borough_id IN (
  SELECT DISTINCT borough_id
  FROM residents_feedback
);

SELECT borough_name
FROM boroughs
ORDER BY borough_name ASC;

SELECT borough_name, average_income
FROM boroughs
ORDER BY average_income DESC;

SELECT AVG(value) AS average_income
FROM borough_statistics
WHERE statistic_name = 'average_income';

SELECT borough_name 
FROM boroughs 
ORDER BY borough_name;
